diff --git a/src/ts_catalog/continuous_agg.c b/src/ts_catalog/continuous_agg.c
index f375b4d14..e897b3494 100644
--- a/src/ts_catalog/continuous_agg.c
+++ b/src/ts_catalog/continuous_agg.c
@@ -1371,8 +1371,8 @@ ts_continuous_agg_bucket_on_interval(Oid bucket_function)
  * set on ContinuousAggBucketFunction, one of time_bucket_ng() versions is used. This is a common
  * procedure used by ts_compute_* below.
  */
-static Datum
-generic_time_bucket(const ContinuousAggBucketFunction *bf, Datum timestamp)
+TSDLLEXPORT Datum
+ts_compute_bucketed_time(const ContinuousAggBucketFunction *bf, Datum timestamp)
 {
 	FuncInfo *func_info = ts_func_cache_get_bucketing_func(bf->bucket_function);
 	Ensure(func_info != NULL, "unable to get bucket function for Oid %d", bf->bucket_function);
@@ -1521,8 +1521,8 @@ ts_compute_inscribed_bucketed_refresh_window_variable(int64 *start, int64 *end,
 	start_old = ts_internal_to_time_value(*start, TIMESTAMPOID);
 	end_old = ts_internal_to_time_value(*end, TIMESTAMPOID);

-	start_aligned = generic_time_bucket(bf, start_old);
-	end_aliged = generic_time_bucket(bf, end_old);
+	start_aligned = ts_compute_bucketed_time(bf, start_old);
+	end_aliged = ts_compute_bucketed_time(bf, end_old);

 	if (DatumGetTimestamp(start_aligned) != DatumGetTimestamp(start_old))
 	{
@@ -1555,8 +1555,8 @@ ts_compute_circumscribed_bucketed_refresh_window_variable(int64 *start, int64 *e
 	 */
 	start_old = ts_internal_to_time_value(*start, TIMESTAMPOID);
 	end_old = ts_internal_to_time_value(*end, TIMESTAMPOID);
-	start_new = generic_time_bucket(bf, start_old);
-	end_new = generic_time_bucket(bf, end_old);
+	start_new = ts_compute_bucketed_time(bf, start_old);
+	end_new = ts_compute_bucketed_time(bf, end_old);

 	if (DatumGetTimestamp(end_new) != DatumGetTimestamp(end_old))
 	{
@@ -1587,7 +1587,7 @@ ts_compute_beginning_of_the_next_bucket_variable(int64 timeval,
 	 */
 	val_old = ts_internal_to_time_value(timeval, TIMESTAMPOID);

-	val_new = generic_time_bucket(bf, val_old);
+	val_new = ts_compute_bucketed_time(bf, val_old);
 	val_new = generic_add_interval(bf, val_new);
 	return ts_time_value_to_internal(val_new, TIMESTAMPOID);
 }
