+			Datum bucketed_datum = ts_compute_bucketed_time(cagg->bucket_function, timestamp_datum);
+			result.end = ts_time_value_to_internal(bucketed_datum, refresh_window->type);
+		}
+		else
+		{
+			result.end = ts_time_bucket_by_type_extended(bucket_width,
+														 refresh_window->end,
+														 refresh_window->type,
+														 NULL_DATUM,
+														 NULL_DATUM);
+		}
 	}
 	return result;
 }
@@ -351,13 +374,18 @@ compute_circumscribed_bucketed_refresh_window(const ContinuousAgg *cagg,
 	InternalTimeRange largest_bucketed_window =
 		get_largest_bucketed_window(refresh_window->type, bucket_width);

-	/* Get offset and origin for bucket function */
+	/* Check if timezone-aware bucketing is needed */
+	bool has_timezone = (bucket_function->bucket_time_timezone != NULL);
+
+	/* Get offset and origin for bucket function (only used when timezone is not set) */
 	NullableDatum offset = INIT_NULL_DATUM;
 	NullableDatum origin = INIT_NULL_DATUM;
-	fill_bucket_offset_origin(cagg, refresh_window, &offset, &origin);
-
-	/* Defined offset and origin in one function is not supported */
-	Assert(offset.isnull == true || origin.isnull == true);
+	if (!has_timezone)
