 	if (refresh_window->start <= largest_bucketed_window.start)
 	{
@@ -367,11 +395,21 @@ compute_circumscribed_bucketed_refresh_window(const ContinuousAgg *cagg,
 	{
 		/* For alignment with a bucket, which includes the start of the refresh window, we just
 		 * need to get start of the bucket. */
-		result.start = ts_time_bucket_by_type_extended(bucket_width,
-													   refresh_window->start,
-													   refresh_window->type,
-													   offset,
-													   origin);
+		if (has_timezone)
+		{
+			/* Use timezone-aware bucketing function */
+			Datum timestamp_datum = ts_internal_to_time_value(refresh_window->start, refresh_window->type);
+			Datum bucketed_datum = ts_compute_bucketed_time(bucket_function, timestamp_datum);
+			result.start = ts_time_value_to_internal(bucketed_datum, refresh_window->type);
+		}
+		else
+		{
+			result.start = ts_time_bucket_by_type_extended(bucket_width,
+														   refresh_window->start,
+														   refresh_window->type,
+														   offset,
+														   origin);
+		}
 	}

 	if (refresh_window->end >= largest_bucketed_window.end)
@@ -389,11 +427,22 @@ compute_circumscribed_bucketed_refresh_window(const ContinuousAgg *cagg,
 		 * bucketing in case we're already at the end of the bucket (we don't
 		 * want to add an extra bucket).  */
 		exclusive_end = ts_time_saturating_sub(refresh_window->end, 1, refresh_window->type);
-		bucketed_end = ts_time_bucket_by_type_extended(bucket_width,
-													   exclusive_end,
-													   refresh_window->type,
-													   offset,
-													   origin);
+
+		if (has_timezone)
+		{
+			/* Use timezone-aware bucketing function */
+			Datum timestamp_datum = ts_internal_to_time_value(exclusive_end, refresh_window->type);
+			Datum bucketed_datum = ts_compute_bucketed_time(bucket_function, timestamp_datum);
+			bucketed_end = ts_time_value_to_internal(bucketed_datum, refresh_window->type);
+		}
+		else
