+			bucketed_end = ts_time_bucket_by_type_extended(bucket_width,
+														   exclusive_end,
+														   refresh_window->type,
+														   offset,
+														   origin);
+		}

 		/* We get the time value for the start of the bucket, so need to add
 		 * bucket_width to get the end of it. */

