  1351→/* Determines if a bucket is using integer or an interval partitioning */
  1352→bool
  1353→ts_continuous_agg_bucket_on_interval(Oid bucket_function)
  1354→{
  1355→	Assert(OidIsValid(bucket_function));
  1356→
  1357→	FuncInfo *func_info = ts_func_cache_get(bucket_function);
  1358→	Ensure(func_info != NULL, "unable to get function info for Oid %d", bucket_function);
  1359→
  1360→	/* The function has to be a currently allowed function or one of the deprecated bucketing
  1361→	 * functions */
  1362→	Assert(func_info->allowed_in_cagg_definition || IS_DEPRECATED_TIME_BUCKET_NG_FUNC(func_info));
  1363→
  1364→	Oid first_bucket_arg = func_info->arg_types[0];
  1365→
  1366→	return first_bucket_arg == INTERVALOID;
  1367→}
  1368→
  1369→/*
  1370→ * Calls the desired time bucket function depending on the arguments. If the experimental flag is
  1371→ * set on ContinuousAggBucketFunction, one of time_bucket_ng() versions is used. This is a common
  1372→ * procedure used by ts_compute_* below.
  1373→ */
  1374→static Datum
  1375→generic_time_bucket(const ContinuousAggBucketFunction *bf, Datum timestamp)
  1376→{
  1377→	FuncInfo *func_info = ts_func_cache_get_bucketing_func(bf->bucket_function);
  1378→	Ensure(func_info != NULL, "unable to get bucket function for Oid %d", bf->bucket_function);
  1379→	bool is_experimental = func_info->origin == ORIGIN_TIMESCALE_EXPERIMENTAL;
  1380→
