		Assert(!isnull);
		int32 hypertable_id = DatumGetInt32(datum);
		Oid relid = ts_hypertable_id_to_relid(hypertable_id, false);
		if (!has_invalidation_trigger(relid))
			hypertables = list_append_unique_int(hypertables, hypertable_id);
